/*!50003 DROP PROCEDURE IF EXISTS `InsertPlateInfo` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `InsertPlateInfo`(IN p_plate VARCHAR(20))
BEGIN
    DECLARE last_status  ENUM('IN','OUT');
    DECLARE v_username   VARCHAR(50) DEFAULT NULL;
    DECLARE parking_rate DECIMAL(10,2) DEFAULT 50.00;

    INSERT INTO number_plates (plate_text) VALUES (p_plate);

    SELECT username INTO v_username
    FROM customer_info WHERE plate_no = p_plate LIMIT 1;

    SELECT in_out_status INTO last_status
    FROM plate_info WHERE plate_no = p_plate
    ORDER BY datetime_entry DESC LIMIT 1;

    IF last_status = 'IN' THEN
        INSERT INTO plate_info (plate_no, username, in_out_status)
        VALUES (p_plate, v_username, 'OUT');

        IF v_username IS NOT NULL THEN
            UPDATE customer_info SET balance = balance - parking_rate
            WHERE username = v_username;

            INSERT INTO profits (date, profit) VALUES (CURDATE(), parking_rate)
            ON DUPLICATE KEY UPDATE profit = profit + parking_rate;
        END IF;
    ELSE
        INSERT INTO plate_info (plate_no, username, in_out_status)
        VALUES (p_plate, v_username, 'IN');
    END IF;

END ;;
DELIMITER ;
